class LoggingApplication : Application() {
    override fun onCreate() {
        super.onCreate()
        initializeLogging(this)
    }

    companion object {
        fun initializeLogging(context: Context) {
            // Plant both debug tree and file logging tree
            Timber.plant(VerboseDebugTree())
            Timber.plant(FileLoggingTree(context))
            Timber.plant(CrashReportingTree())

            // Set global uncaught exception handler
            val defaultHandler = Thread.getDefaultUncaughtExceptionHandler()
            Thread.setDefaultUncaughtExceptionHandler { thread, throwable ->
                Timber.e(throwable, "UNCAUGHT EXCEPTION on thread: ${thread.name}")
                ExceptionLogger.logException("UncaughtException", throwable, mapOf("thread" to thread.name))
                defaultHandler?.uncaughtException(thread, throwable)
            }

            Timber.v("Logging system initialized - Device: ${Build.MANUFACTURER} ${Build.MODEL}, " +
                    "Android ${Build.VERSION.RELEASE} (API ${Build.VERSION.SDK_INT})")
        }
    }
}

