/**
 * Verbose debug tree that includes class name, method name, and line number
 */
class VerboseDebugTree : Timber.DebugTree() {
    private val dateFormat = SimpleDateFormat("yyyy-MM-dd HH:mm:ss.SSS", Locale.US)

    override fun createStackElementTag(element: StackTraceElement): String {
        return "(${element.fileName}:${element.lineNumber}) ${element.methodName}"
    }

    override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
        val timestamp = dateFormat.format(Date())
        val priorityChar = when (priority) {
            Log.VERBOSE -> "V"
            Log.DEBUG -> "D"
            Log.INFO -> "I"
            Log.WARN -> "W"
            Log.ERROR -> "E"
            Log.ASSERT -> "A"
            else -> "?"
        }
        val formattedMessage = "[$timestamp][$priorityChar][$tag] $message"
        super.log(priority, "AppLog", formattedMessage, t)
    }
}

/**
 * Tree that writes logs to a file for later retrieval
 */
class FileLoggingTree(private val context: Context) : Timber.Tree() {
    private val dateFormat = SimpleDateFormat("yyyy-MM-dd HH:mm:ss.SSS", Locale.US)
    private val fileDateFormat = SimpleDateFormat("yyyy-MM-dd", Locale.US)
    private val executor = Executors.newSingleThreadExecutor()
    private val logBuffer = ConcurrentLinkedQueue<String>()
    private val bufferSize = 50

    override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
        val timestamp = dateFormat.format(Date())
        val priorityChar = when (priority) {
            Log.VERBOSE -> "V"
            Log.DEBUG -> "D"
            Log.INFO -> "I"
            Log.WARN -> "W"
            Log.ERROR -> "E"
            Log.ASSERT -> "A"
            else -> "?"
        }

        val logLine = buildString {
            append("$timestamp [$priorityChar] [$tag] $message")
            if (t != null) {
                append("\n")
                append(getStackTraceString(t))
            }
            append("\n")
        }

        logBuffer.add(logLine)

        if (logBuffer.size >= bufferSize || priority >= Log.ERROR) {
            flushBuffer()
        }
    }

    private fun flushBuffer() {
        val entries = mutableListOf<String>()
        while (logBuffer.isNotEmpty()) {
            logBuffer.poll()?.let { entries.add(it) }
        }
        if (entries.isEmpty()) return

        executor.execute {
            try {
                val logDir = File(context.filesDir, "logs")
                if (!logDir.exists()) logDir.mkdirs()

                // Clean old log files (keep last 7 days)
                cleanOldLogs(logDir, 7)

                val fileName = "app_log_${fileDateFormat.format(Date())}.txt"
                val logFile = File(logDir, fileName)

                FileWriter(logFile, true).use { writer ->
                    entries.forEach { writer.write(it) }
                }
            } catch (e: Exception) {
                Log.e("FileLoggingTree", "Failed to write log to file", e)
            }
        }
    }

    private fun cleanOldLogs(logDir: File, keepDays: Int) {
        val cutoff = System.currentTimeMillis() - (keepDays * 24 * 60 * 60 * 1000L)
        logDir.listFiles()?.forEach { file ->
            if (file.lastModified() < cutoff) {
                file.delete()
            }
        }
    }

    private fun getStackTraceString(t: Throwable): String {
        val sw = StringWriter()
        val pw = PrintWriter(sw)
        t.printStackTrace(pw)
        pw.flush()
        return sw.toString()
    }
}

/**
 * Tree specifically for crash/error reporting aggregation
 */
class CrashReportingTree : Timber.Tree() {
    override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
        if (priority < Log.WARN) return

        // In production, you would send this to your crash reporting service
        // e.g., Firebase Crashlytics, Sentry, etc.
        CrashReportAggregator.record(priority, tag, message, t)
    }
}

/**
 * Simple in-memory crash report aggregator (replace with real service in production)
 */
object CrashReportAggregator {
    private val reports = ConcurrentLinkedQueue<CrashReport>()
    private const val MAX_REPORTS = 500

    data class CrashReport(
        val timestamp: Long,
        val priority: Int,
        val tag: String?,
        val message: String,
        val throwable: Throwable?
    )

    fun record(priority: Int, tag: String?, message: String, t: Throwable?) {
        if (reports.size >= MAX_REPORTS) {
            reports.poll()
        }
        reports.add(CrashReport(System.currentTimeMillis(), priority, tag, message, t))
    }

    fun getReports(): List<CrashReport> = reports.toList()

    fun clear() = reports.clear()
}

