object AuthLogger {
    private const val TAG = "AUTH"

    fun logLoginAttempt(username: String, method: String, metadata: Map<String, String> = emptyMap()) {
        Timber.tag(TAG).v(buildString {
            append("LOGIN ATTEMPT | user: ${sanitizeUsername(username)} | method: $method")
            if (metadata.isNotEmpty()) {
                append(" | metadata: ${formatMetadata(metadata)}")
            }
            append(" | timestamp: ${System.currentTimeMillis()}")
        })
    }

    fun logLoginSuccess(
        username: String,
        method: String,
        userId: String,
        sessionInfo: Map<String, String> = emptyMap()
    ) {
        Timber.tag(TAG).i(buildString {
            append("LOGIN SUCCESS | user: ${sanitizeUsername(username)} | method: $method")
            append(" | userId: $userId")
            if (sessionInfo.isNotEmpty()) {
                append(" | session: ${formatMetadata(sessionInfo)}")
            }
            append(" | timestamp: ${System.currentTimeMillis()}")
        })
    }

    fun logLoginFailure(
        username: String,
        method: String,
        reason: String,
        errorCode: Int? = null,
        exception: Throwable? = null
    ) {
        Timber.tag(TAG).w(exception, buildString {
            append("LOGIN FAILURE | user: ${sanitizeUsername(username)} | method: $method")
            append(" | reason: $reason")
            errorCode?.let { append(" | errorCode: $it") }
            append(" | timestamp: ${System.currentTimeMillis()}")
        })
    }

    fun logLogout(userId: String, reason: String = "user_initiated") {
        Timber.tag(TAG).i("LOGOUT | userId: $userId | reason: $reason | timestamp: ${System.currentTimeMillis()}")
    }

    fun logTokenRefresh(userId: String, success: Boolean, error: String? = null) {
        if (success) {
            Timber.tag(TAG).v("TOKEN REFRESH SUCCESS | userId: $userId | timestamp: ${System.currentTimeMillis()}")
        } else {
            Timber.tag(TAG).w("TOKEN REFRESH FAILURE | userId: $userId | error: $error | timestamp: ${System.currentTimeMillis()}")
        }
    }

    fun logRegistrationAttempt(username: String, email: String) {
        Timber.tag(TAG).v("REGISTRATION ATTEMPT | user: ${sanitizeUsername(username)} | email: ${sanitizeEmail(email)} | timestamp: ${System.currentTimeMillis()}")
    }

    fun logRegistrationSuccess(username: String, userId: String) {
        Timber.tag(TAG).i("REGISTRATION SUCCESS | user: ${sanitizeUsername(username)} | userId: $userId | timestamp: ${System.currentTimeMillis()}")
    }

    fun logRegistrationFailure(username: String, reason: String, exception: Throwable? = null) {
        Timber.tag(TAG).w(exception, "REGISTRATION FAILURE | user: ${sanitizeUsername(username)} | reason: $reason | timestamp: ${System.currentTimeMillis()}")
    }

    fun logPasswordResetRequest(email: String, success: Boolean, error: String? = null) {
        if (success) {
            Timber.tag(TAG).i("PASSWORD RESET REQUESTED | email: ${sanitizeEmail(email)} | timestamp: ${System.currentTimeMillis()}")
        } else {
            Timber.tag(TAG).w("PASSWORD RESET FAILED | email: ${sanitizeEmail(email)} | error: $error | timestamp: ${System.currentTimeMillis()}")
        }
    }

    fun logBiometricAuth(userId: String, success: Boolean, error: String? = null) {
        if (success) {
            Timber.tag(TAG).i("BIOMETRIC AUTH SUCCESS | userId: $userId | timestamp: ${System.currentTimeMillis()}")
        } else {
            Timber.tag(TAG).w("BIOMETRIC AUTH FAILURE | userId: $userId | error: $error | timestamp: ${System.currentTimeMillis()}")
        }
    }

    private fun sanitizeUsername(username: String): String {
        if (username.length <= 3) return "***"
        return "${username.take(2)}${"*".repeat(username.length - 3)}${username.last()}"
    }

    private fun sanitizeEmail(email: String): String {
        val parts = email.split("@")
        if (parts.size != 2) return "***@***"
        val localPart = parts[0]
        val domain = parts[1]
        val sanitizedLocal = if (localPart.length <= 2) "**" else "${localPart.first()}${"*".repeat(localPart.length - 2)}${localPart.last()}"
        return "$sanitizedLocal@$domain"
    }

    private fun formatMetadata(metadata: Map<String, String>): String {
        return metadata.entries.joinToString(", ") { "${it.key}=${it.value}" }
    }
}

