// 4. Database Query Logger
// ============================================================
object DatabaseLogger {
    private const val TAG = "DATABASE"

    fun logQuery(
        query: String,
        parameters: Map<String, Any?> = emptyMap(),
        tableName: String? = null,
        operationType: DatabaseOperation = DatabaseOperation.SELECT
    ) {
        val startTime = System.nanoTime()
        Timber.tag(TAG).v(buildString {
            append("QUERY START | operation: ${operationType.name}")
            tableName?.let { append(" | table: $it") }
            append(" | query: $query")
            if (parameters.isNotEmpty()) {
                append(" | params: ${formatParams(parameters)}")
            }
            append(" | timestamp: ${System.currentTimeMillis()}")
        })
    }

    fun logQueryResult(
        query: String,
        rowCount: Int,
        executionTimeMs: Long,
        tableName: String? = null,
        operationType: DatabaseOperation = DatabaseOperation.SELECT
    ) {
        val logLevel = when {
            executionTimeMs > 1000 -> Log.WARN
            executionTimeMs > 500 -> Log.INFO
            else -> Log.VERBOSE
        }

        val message = buildString {
            append("QUERY COMPLETE | operation: ${operationType.name}")
            tableName?.let { append(" | table: $it") }
            append(" | query: ${query.take(200)}")
            append(" | rows: $rowCount")
            append(" | duration: ${executionTimeMs}ms")
            if (executionTimeMs > 500) append(" | SLOW_QUERY")
            append(" | timestamp: ${System.currentTimeMillis()}")
        }

        when (logLevel) {
            Log.WARN -> Timber.tag(TAG).w(message)
            Log.INFO -> Timber.tag(TAG).i(message)
            else -> Timber.tag(TAG).v(message)
        }
    }

    fun logQueryError(
        query: String,
        parameters: Map<String, Any?> = emptyMap(),
        exception: Throwable,
        tableName: String? = null,
        operationType: DatabaseOperation = DatabaseOperation.SELECT
    ) {
        Timber.tag(TAG).e(exception, buildString {
            append("QUERY ERROR | operation: ${operationType.name}")
            tableName?.let { append(" | table: $it") }
            append(" | query: $query")
            if (parameters.isNotEmpty()) {
                append(" | params: ${formatParams(parameters)}")
            }
            append(" | error: ${exception.message}")
            append(" | timestamp: ${System.currentTimeMillis()}")
        })
    }

    fun logTransaction(transactionId: String, action: String, tables: List<String> = emptyList()) {
        Timber.tag(TAG).v(buildString {
            append("TRANSACTION | id: $transactionId | action: $action")
            if (tables.isNotEmpty()) {
                append(" | tables: ${tables.joinToString(", ")}")
            }
            append(" | timestamp: ${System.currentTimeMillis()}")
        })
    }

    fun logMigration(fromVersion: Int, toVersion: Int, success: Boolean, durationMs: Long, error: String? = null) {
        if (success) {
            Timber.tag(TAG).i("MIGRATION SUCCESS | from: v$fromVersion | to: v$toVersion | duration: ${durationMs}ms")
        } else {
            Timber.tag(TAG).e("MIGRATION FAILURE | from: v$fromVersion | to: v$toVersion | duration: ${durationMs}ms | error: $error")
        }
    }

    fun logDatabaseOpen(dbName: String, version: Int, sizeBytes: Long) {
        Timber.tag(TAG).i("DATABASE OPEN | name: $dbName | version: $version | size: ${formatSize(sizeBytes)}")
    }

    fun logDatabaseClose(dbName: String) {
        Timber.tag(TAG).i("DATABASE CLOSE | name: $dbName | timestamp: ${System.currentTimeMillis()}")
    }

    private fun formatParams(params: Map<String, Any?>): String {
        return params.entries.joinToString(", ") { entry ->
            val value = when (val v = entry.value) {
                null -> "NULL"
                is String -> if (v.length > 100) "'${v.take(100)}...(truncated)'" else "'$v'"
                is ByteArray -> "BLOB(${v.size} bytes)"
                else -> v.toString()
            }
            "${entry.key}=$value"
        }
    }

    private fun formatSize(bytes: Long): String {
        return when {
            bytes < 1024 -> "$bytes B"
            bytes < 1024 * 1024 -> "${bytes / 1024} KB"
            else -> "${bytes / (1024 * 1024)} MB"
        }
    }

    enum class DatabaseOperation {
        SELECT, INSERT, UPDATE, DELETE, CREATE, ALTER, DROP, TRANSACTION_BEGIN, TRANSACTION_COMMIT, TRANSACTION_ROLLBACK
    }
}

/**
 * Helper class to wrap database calls with automatic timing and logging
 */
class DatabaseQueryTimer(
    private val query: String,
    private val parameters: Map<String, Any?> = emptyMap(),
    private val tableName: String? = null,
    private val operationType: DatabaseLogger.DatabaseOperation = DatabaseLogger.DatabaseOperation.SELECT
) {
    private val startTime = System.currentTimeMillis()

    init {
        DatabaseLogger.logQuery(query, parameters, tableName, operationType)
    }

    fun <T> complete(result: T, rowCount: Int = 0): T {
        val duration = System.currentTimeMillis() - startTime
        DatabaseLogger.logQueryResult(query, rowCount, duration, tableName, operationType)
        return result
    }

    fun error(exception: Throwable) {
        DatabaseLogger.logQueryError(query, parameters, exception, tableName, operationType)
    }
}

