/**
 * Comprehensive OkHttp interceptor that logs full request and response details
 */
class ComprehensiveLoggingInterceptor(
    private val sensitiveHeaders: Set<String> = setOf("Authorization", "Cookie", "Set-Cookie"),
    private val maxBodyLogSize: Long = 1024 * 100, // 100KB
    private val redactSensitiveHeaders: Boolean = false // Set to true in production for security
) : Interceptor {

    companion object {
        private const val TAG = "API"
    }

    override fun intercept(chain: Interceptor.Chain): Response {
        val request = chain.request()
        val requestId = UUID.randomUUID().toString().take(8)
        val startTime = System.currentTimeMillis()

        logRequest(request, requestId)

        val response: Response
        try {
            response = chain.proceed(request)
        } catch (e: Exception) {
            val duration = System.currentTimeMillis() - startTime
            logNetworkError(request, requestId, duration, e)
            throw e
        }

        val duration = System.currentTimeMillis() - startTime
        return logResponse(response, requestId, duration)
    }

    private fun logRequest(request: Request, requestId: String) {
        Timber.tag(TAG).v(buildString {
            append("\n╔══════════════════════════════════════════════════════════")
            append("\n║ REQUEST [$requestId]")
            append("\n╠══════════════════════════════════════════════════════════")
            append("\n║ Method: ${request.method}")
            append("\n║ URL: ${request.url}")
            append("\n║ Timestamp: ${SimpleDateFormat("yyyy-MM-dd HH:mm:ss.SSS", Locale.US).format(Date())}")
            append("\n╠── Headers ────────────────────────────────────────────")

            request.headers.forEach { (name, value) ->
                val displayValue = if (redactSensitiveHeaders && sensitiveHeaders.contains(name)) {
                    "[REDACTED]"
                } else {
                    value
                }
                append("\n║   $name: $displayValue")
            }

            val body = request.body
            if (body != null) {
                append("\n╠── Body ───────────────────────────────────────────────")
                append("\n║   Content-Type: ${body.contentType()}")
                append("\n║   Content-Length: ${body.contentLength()} bytes")

                try {
                    val buffer = Buffer()
                    body.writeTo(buffer)
                    val bodyString = buffer.readUtf8()
                    if (bodyString.length <= maxBodyLogSize) {
                        append("\n║   Body Content:")
                        bodyString.lines().forEach { line ->
                            append("\n║     $line")
                        }
                    } else {
                        append("\n║   Body Content: [TRUNCATED - ${bodyString.length} bytes, max $maxBodyLogSize]")
                        append("\n║     ${bodyString.take(maxBodyLogSize.toInt())}...")
                    }
                } catch (e: Exception) {
                    append("\n║   Body Content: [UNABLE TO READ - ${e.message}]")
                }
            } else {
                append("\n║   No request body")
            }

            append("\n╚══════════════════════════════════════════════════════════")
        })
    }

    private fun logResponse(response: Response, requestId: String, durationMs: Long): Response {
        val responseBody = response.body
        val contentType = responseBody?.contentType()
        val bodyString = responseBody?.string() ?: ""

        val logPriority = when {
            response.code >= 500 -> Log.ERROR
            response.code >= 400 -> Log.WARN
            durationMs > 5000 -> Log.WARN
            else -> Log.VERBOSE
        }

        val message = buildString {
            append("\n╔══════════════════════════════════════════════════════════")
            append("\n║ RESPONSE [$requestId]")
            append("\n╠══════════════════════════════════════════════════════════")
            append("\n║ Status: ${response.code} ${response.message}")
            append("\n║ URL: ${response.request.url}")
            append("\n║ Duration: ${durationMs}ms")
            if (durationMs > 3000) append(" ⚠️ SLOW")
            append("\n║ Protocol: ${response.protocol}")
            append("\n║ Timestamp: ${SimpleDateFormat("yyyy-MM-dd HH:mm:ss.SSS", Locale.US).format(Date())}")
            append("\n╠── Response Headers ───────────────────────────────────")

            response.headers.forEach { (name, value) ->
                val displayValue = if (redactSensitiveHeaders && sensitiveHeaders.contains(name)) {
                    "[REDACTED]"
                } else {
                    value
                }
                append("\n║   $name: $displayValue")
            }

            append("\n╠── Response Body ──────────────────────────────────────")
            if (bodyString.isNotEmpty()) {
                append("\n║   Content-Type: $contentType")
                append("\n║   Content-Length: ${bodyString.length} bytes")
                if (bodyString.length <= maxBodyLogSize) {
                    append("\n║   Body Content:")
                    bodyString.lines().forEach { line ->
                        append("\n║     $line")
                    }
                } else {
                    append("\n║   Body Content: [TRUNCATED - ${bodyString.length} bytes]")
                    append("\n║     ${bodyString.take(maxBodyLogSize.toInt())}...")
                }
            } else {
                append("\n║   No response body")
            }

            if (response.code >= 400) {
                append("\n╠── ERROR DETAILS ──────────────────────────────────────")
                append("\n║   HTTP Error: ${response.code} ${response.message}")
                append("\n║   Request: ${response.request.method} ${response.request.url}")
            }

            append("\n╚══════════════════════════════════════════════════════════")
        }

        when (logPriority) {
            Log.ERROR -> Timber.tag(TAG).e(message)
            Log.WARN -> Timber.tag(TAG).w(message)
            else -> Timber.tag(TAG).v(message)
        }

        // Reconstruct the response since we consumed the body
        val newResponseBody = bodyString.toResponseBody(contentType)
        return response.newBuilder().body(newResponseBody).build()
    }

    private fun logNetworkError(request: Request, requestId: String, durationMs: Long, exception: Exception) {
        Timber.tag(TAG).e(exception, buildString {
            append("\n╔══════════════════════════════════════════════════════════")
            append("\n║ NETWORK ERROR [$requestId]")
            append("\n╠══════════════════════════════════════════════════════════")
            append("\n║ URL: ${request.url}")
            append("\n║ Method: ${request.method}")
            append("\n║ Duration: ${durationMs}ms")
            append("\n║ Error Type: ${exception.javaClass.simpleName}")
            append("\n║ Error Message: ${exception.message}")
            append("\n║ Timestamp: ${SimpleDateFormat("yyyy-MM-dd HH:mm:ss.SSS", Locale.US).format(Date())}")
            append("\n╠── Stack Trace ────────────────────────────────────────")
            val sw = StringWriter()
            exception.printStackTrace(PrintWriter(sw))
            sw.toString().lines().forEach { line ->
                append("\n║   $line")
            }
            append("\n╚══════════════════════════════════════════════════════════")
        })
    }
}

