// 6. Exception Logger
// ============================================================
object ExceptionLogger {
    private const val TAG = "EXCEPTION"

    fun logException(
        context: String,
        throwable: Throwable,
        additionalData: Map<String, Any?> = emptyMap()
    ) {
        Timber.tag(TAG).e(throwable, buildString {
            append("\n┌──────────────────────────────────────────────────────────")
            append("\n│ EXCEPTION CAUGHT")
            append("\n├──────────────────────────────────────────────────────────")
            append("\n│ Context: $context")
            append("\n│ Type: ${throwable.javaClass.canonicalName}")
            append("\n│ Message: ${throwable.message}")
            append("\n│ Timestamp: ${SimpleDateFormat("yyyy-MM-dd HH:mm:ss.SSS", Locale.US).format(Date())}")
            append("\n│ Thread: ${Thread.currentThread().name}")

            if (additionalData.isNotEmpty()) {
                append("\n├── Additional Data ────────────────────────────────────")
                additionalData.forEach { (key, value) ->
                    append("\n│   $key: $value")
                }
            }

            append("\n├── Stack Trace ────────────────────────────────────────")
            val sw = StringWriter()
            throwable.printStackTrace(PrintWriter(sw))
            sw.toString().lines().forEach { line ->
                append("\n│   $line")
            }

            // Log cause chain
            var cause = throwable.cause
            var causeDepth = 1
            while (cause != null) {
                append("\n├── Cause #$causeDepth ──────────────────────────────────")
                append("\n│   Type: ${cause.javaClass.canonicalName}")
                append("\n│   Message: ${cause.message}")
                val causeSw = StringWriter()
                cause.printStackTrace(PrintWriter(causeSw))
                causeSw.toString().lines().take(10).forEach { line ->
                    append("\n│   $line")
                }
                cause = cause.cause
                causeDepth++
            }

            append("\n└──────────────────────────────────────────────────────────")
        })
    }

    fun logWarning(context: String, message: String, additionalData: Map<String, Any?> = emptyMap()) {
        Timber.tag(TAG).w(buildString {
            append("WARNING | context: $context | message: $message")
            if (additionalData.isNotEmpty()) {
                append(" | data: $additionalData")
            }
        })
    }
}

// ============================================================
// 7. Performance Logger
// ============================================================
object PerformanceLogger {
    private const val TAG = "PERF"
    private val timers = mutableMapOf<String, Long>()

    fun startTimer(operationId: String, description: String = "") {
        timers[operationId] = System.currentTimeMillis()
        Timber.tag(TAG).v("TIMER START | id: $operationId | desc: $description | timestamp: ${System.currentTimeMillis()}")
    }

    fun stopTimer(operationId: String, additionalInfo: String = ""): Long {
        val startTime = timers.remove(operationId)
        val duration = if (startTime != null) System.currentTimeMillis() - startTime else -1

        val message = buildString {
            append("TIMER STOP | id: $operationId | duration: ${duration}ms")
            if (additionalInfo.isNotEmpty()) append(" | info: $additionalInfo")
            if (duration > 3000) append(" | ⚠️ SLOW OPERATION")
        }

        if (duration > 3000) {
            Timber.tag(TAG).w(message)
        } else {
            Timber.tag(TAG).v(message)
        }

        return duration
    }

    fun logMemoryUsage(context: String = "") {
        val runtime = Runtime.getRuntime()
        val usedMemory = (runtime.totalMemory() - runtime.freeMemory()) / 1024 / 1024
        val maxMemory = runtime.maxMemory() / 1024 / 1024
        val freeMemory = runtime.freeMemory() / 1024 / 1024

        Timber.tag(TAG).v(buildString {
            append("MEMORY | used: ${usedMemory}MB | free: ${freeMemory}MB | max: ${maxMemory}MB")
            append(" | usage: ${(usedMemory * 100 / maxMemory)}%")
            if (context.isNotEmpty()) append(" | context: $context")
            if (usedMemory * 100 / maxMemory > 80) append(" | ⚠️ HIGH MEMORY USAGE")
        })
    }
}

