// ============================================================
// 10. OkHttpClient Builder Helper
// ============================================================
object LoggingHttpClient {
    fun createClient(
        redactHeaders: Boolean = false,
        maxBodyLogSize: Long = 1024 * 100
    ): OkHttpClient {
        return OkHttpClient.Builder()
            .addInterceptor(ComprehensiveLoggingInterceptor(
                redactSensitiveHeaders = redactHeaders,
                maxBodyLogSize = maxBodyLogSize
            ))
            .build()
    }
}

// ============================================================
// 11. Log File Manager - Retrieve and share logs
// ============================================================
object LogFileManager {
    fun getLogFiles(context: Context): List<File> {
        val logDir = File(context.filesDir, "logs")
        return logDir.listFiles()?.toList()?.sortedByDescending { it.lastModified() } ?: emptyList()
    }

    fun getLatestLogContent(context: Context, maxLines: Int = 1000): String {
        val files = getLogFiles(context)
        if (files.isEmpty()) return "No log files found"

        return files.first().readLines().takeLast(maxLines).joinToString("\n")
    }

    fun getAllLogsContent(context: Context): String {
        return getLogFiles(context).joinToString("\n\n=== FILE BOUNDARY ===\n\n") { file ->
            "=== ${file.name} ===\n${file.readText()}"
        }
    }

    fun clearLogs(context: Context) {
        val logDir = File(context.filesDir, "logs")
        logDir.listFiles()?.forEach { it.delete() }
        Timber.i("All log files cleared")
    }

    fun getLogsSummary(context: Context): String {
        val files = getLogFiles(context)
        val totalSize = files.sumOf { it.length() }
        return buildString {
            append("Log Files Summary:\n")
            append("Total files: ${files.size}\n")
            append("Total size: ${totalSize / 1024} KB\n")
            files.forEach { file ->
                append("  ${file.name} - ${file.length() / 1024} KB - ${Date(file.lastModified())}\n")
            }
        }
    }
}

