object LoggingExamples {

    fun demonstrateAuthLogging() {
        // Login attempt
        AuthLogger.logLoginAttempt("john_doe", "email_password", mapOf("ip" to "192.168.1.1", "device" to "Pixel 7"))

        // Successful login
        AuthLogger.logLoginSuccess(
            "john_doe",
            "email_password",
            "usr_123456",
            mapOf("sessionId" to "sess_abc", "expiresIn" to "3600")
        )

        // Failed login
        AuthLogger.logLoginFailure(
            "john_doe",
            "email_password",
            "Invalid credentials",
            errorCode = 401
        )

        // Token refresh
        AuthLogger.logTokenRefresh("usr_123456", success = true)

        // Biometric auth
        AuthLogger.logBiometricAuth("usr_123456", success = false, error = "Fingerprint not recognized")

        // Logout
        AuthLogger.logLogout("usr_123456", "session_expired")
    }

    fun demonstrateDatabaseLogging() {
        // Using DatabaseQueryTimer for automatic timing
        val timer = DatabaseQueryTimer(
            query = "SELECT * FROM users WHERE age > ? AND city = ?",
            parameters = mapOf("age" to 25, "city" to "New York"),
            tableName = "users",
            operationType = DatabaseLogger.DatabaseOperation.SELECT
        )

        try {
            // Simulate query execution
            val results = listOf("user1", "user2", "user3")
            timer.complete(results, rowCount = results.size)
        } catch (e: Exception) {
            timer.error(e)
        }

        // Manual logging
        DatabaseLogger.logQuery(
            "INSERT INTO orders (user_id, product_id, quantity) VALUES (?, ?, ?)",
            mapOf("user_id" to 123, "product_id" to 456, "quantity" to 2),
            "orders",
            DatabaseLogger.DatabaseOperation.INSERT
        )

        DatabaseLogger.logTransaction("txn_001", "BEGIN", listOf("users", "orders"))
        DatabaseLogger.logTransaction("txn_001", "COMMIT")
    }

    fun demonstrateExceptionLogging() {
        try {
            throw RuntimeException("Something went wrong", IllegalStateException("Invalid state"))
        } catch (e: Exception) {
            ExceptionLogger.logException(
                context = "OrderProcessing.processPayment",
                throwable = e,
                additionalData = mapOf(
                    "orderId" to "ord_789",
                    "userId" to "usr_123",
                    "amount" to 99.99,
                    "currency" to "USD"
                )
            )
        }
    }

    fun demonstratePerformanceLogging() {
        PerformanceLogger.startTimer("data_sync", "Full data synchronization")
        // ... do work ...
        PerformanceLogger.stopTimer("data_sync", "Synced 1500 records")

        PerformanceLogger.logMemoryUsage("After data sync")
    }

    fun demonstrateUserActionLogging() {
        UserActionLogger.logScreenView("HomeScreen", source = "app_launch")
        UserActionLogger.logButtonClick("btn_search", "HomeScreen")
        UserActionLogger.logSearch("kotlin tutorials", resultsCount = 42, screenName = "SearchScreen")
        UserActionLogger.logNavigation("HomeScreen", "DetailScreen", trigger = "item_click")
    }
}